        button.tag = i; // 使用索引作为临时tag
        [self.buttonsScrollView addSubview:button];
        [self.paymentButtons addObject:button];
    }
}

- (void)updateButtonsConstraints {
    CGFloat buttonHeight = ZOOM(32);
    CGFloat spacing = ZOOM(8);
    CGFloat badgeExtraSpace = ZOOM(8);

    // 只处理可见的按钮
    NSMutableArray *visibleButtons = [NSMutableArray array];
    for (UIButton *button in self.paymentButtons) {
        if (!button.hidden) {
            [visibleButtons addObject:button];
        }
    }

    if (visibleButtons.count == 0) return;

    // 存储每个按钮的宽度
    NSMutableArray *buttonWidths = [NSMutableArray array];
    CGFloat totalContentWidth = ZOOM(16);

    // 计算每个按钮的宽度
    for (NSInteger i = 0; i < visibleButtons.count; i++) {
        UIButton *button = visibleButtons[i];
        NSDictionary *methodData = [self methodDataForButton:button];

        CGFloat buttonWidth = ZOOM(94);
        if (methodData && [methodData[@"title"] isEqualToString:@"Apple Pay"]) {
            buttonWidth = ZOOM(111);
        }

        [buttonWidths addObject:@(buttonWidth)];
        totalContentWidth += buttonWidth;
    }

    totalContentWidth += (visibleButtons.count - 1) * spacing + ZOOM(16);

    // 设置按钮位置
    CGFloat currentX = ZOOM(16);
    for (NSInteger i = 0; i < visibleButtons.count; i++) {
        UIButton *button = visibleButtons[i];
        CGFloat buttonWidth = [buttonWidths[i] floatValue];

        [button mas_remakeConstraints:^(MASConstraintMaker *make) {
            make.top.equalTo(self.buttonsScrollView).offset(badgeExtraSpace);
