- (UIButton *)createButtonWithLeftIcon:(NSString *)leftIconName title:(NSString *)title {
    UIButton *button = [[UIButton alloc] init];
    button.backgroundColor = [UIColor clearColor];
    button.layer.cornerRadius = ZOOM(8);

    UIView *containerView = [[UIView alloc] init];
    containerView.userInteractionEnabled = NO;
    containerView.layer.cornerRadius = ZOOM(8);
    containerView.layer.borderColor = WBColorHex(0x999999).CGColor;
    containerView.layer.borderWidth = self.isFromSinglePage ? ZOOM(0.5) : ZOOM(1);
    [button addSubview:containerView];

    [containerView mas_makeConstraints:^(MASConstraintMaker *make) {
        make.edges.equalTo(button);
    }];

    UIImageView *leftImageView = [[UIImageView alloc] init];
    leftImageView.image = [UIImage imageNamed:leftIconName];
    leftImageView.contentMode = UIViewContentModeScaleAspectFit;
    [containerView addSubview:leftImageView];

    UILabel *titleLabel = [[UILabel alloc] init];
    titleLabel.text = title;
    titleLabel.font = [UIFont systemFontOfSize:ZOOM(12) weight:UIFontWeightMedium];
    titleLabel.textColor = WBColorHex(0x999999);
    titleLabel.textAlignment = NSTextAlignmentCenter;
    [containerView addSubview:titleLabel];

    [leftImageView mas_makeConstraints:^(MASConstraintMaker *make) {
        make.centerY.equalTo(containerView);
        make.left.equalTo(containerView).offset(ZOOM(6));
        make.width.height.mas_equalTo(ZOOM(20));
    }];

    [titleLabel mas_makeConstraints:^(MASConstraintMaker *make) {
        make.centerY.equalTo(containerView);
        make.right.equalTo(containerView).offset(ZOOM(-6));
    }];

    return button;
}


#pragma mark - Event Handling

- (void)setUpEvents {
    for (UIButton *button in self.paymentButtons) {
        [button addTarget:self action:@selector(selectPayMethod:) forControlEvents:UIControlEventTouchUpInside];
    }
}

- (void)selectPayMethod:(UIButton *)sender {
    [sender showClickedAnimationWithLevel:2];

    NSDictionary *methodData = [self methodDataForButton:sender];

    if (methodData) {
        self.selectedPayMethod = (WBPaymentMethod)[methodData[@"type"] integerValue];
        self.selectedPayMethodName = methodData[@"title"];
        self.selectedPayMethodUrl = methodData[@"link"];
        self.selectedPayMethodId = methodData[@"id"];
        [self updateButtonStyles];
    }

}

// 根据按钮找到对应的支付方式数据
- (NSDictionary *)methodDataForButton:(UIButton *)button {
    NSInteger index = [self.paymentButtons indexOfObject:button];
    if (index != NSNotFound && index < self.serverPayMethods.count) {
        return self.serverPayMethods[index];
    }
    return nil;
}


#pragma mark - Data Manage

- (void)updateWithServerPayMethods:(NSArray<NSDictionary *> *)payMethods {
    NSMutableArray *tempArray = [NSMutableArray array];
    self.selectedPayMethod = WBPaymentMethodNone;

    for (NSDictionary *payMethod in payMethods) {
        NSMutableDictionary *newDict = [NSMutableDictionary dictionary];

        newDict[@"id"] = payMethod[@"id"];
        newDict[@"type"] = payMethod[@"type"];
        newDict[@"showBadge"] = payMethod[@"showBadge"];
        newDict[@"badgeValue"] = payMethod[@"badgeValue"];
        newDict[@"sort"] = payMethod[@"sort"];
        newDict[@"discount"] = payMethod[@"discount"];
        newDict[@"link"] = payMethod[@"link"];

        switch ([newDict[@"type"] integerValue]) {
            case WBPaymentMethodApplePay:
                newDict[@"title"] = @"Apple Pay";
                newDict[@"icon"] = @"ApplePay";
                break;
            case WBPaymentMethodAliPay:
                newDict[@"title"] = @"支付宝";
                newDict[@"icon"] = @"支付宝";
                break;
            case WBPaymentMethodWechatPay:
                newDict[@"title"] = @"微信";
                newDict[@"icon"] = @"微信支付";
                break;
            case WBPaymentMethodTaoBaoPay:
                newDict[@"title"] = @"淘宝";
                newDict[@"icon"] = @"淘宝";
                break;
            default:
                break;
        }

        [tempArray addObject:newDict];
    }

    self.serverPayMethods = [tempArray sortedArrayUsingComparator:^NSComparisonResult(NSDictionary *obj1, NSDictionary *obj2) {
        return [obj1[@"sort"] compare:obj2[@"sort"]];
    }];

    if (self.serverPayMethods.count > 0) {
        NSDictionary *firstMethod = self.serverPayMethods[0];
        self.selectedPayMethod = (WBPaymentMethod)[firstMethod[@"type"] integerValue];
        self.selectedPayMethodName = firstMethod[@"title"];
        self.selectedPayMethodUrl = firstMethod[@"link"];
        self.selectedPayMethodId = firstMethod[@"id"];
    }

    [self updateButtonVisibility];
    [self updateButtonStyles];
}

- (void)updateButtonVisibility {
    for (UIButton *button in self.paymentButtons) {
        button.hidden = YES;
    }

    for (NSInteger i = 0; i < MIN(self.serverPayMethods.count, self.maxButtonCount); i++) {
        NSDictionary *method = self.serverPayMethods[i];
        UIButton *button = self.paymentButtons[i];

        button.hidden = NO;
        button.tag = [method[@"type"] integerValue];
        button.clipsToBounds = NO;

        UILabel *badgeLabel = [button viewWithTag:1001];
        if (!badgeLabel) {
            badgeLabel = [[UILabel alloc] init];
            badgeLabel.tag = 1001;
            badgeLabel.textColor = [UIColor whiteColor];
            badgeLabel.font = WBPrimaryBoldFont(10);
            badgeLabel.textAlignment = NSTextAlignmentCenter;
            [button addSubview:badgeLabel];
        }

        UIImageView *badgeLabelImageView = [button viewWithTag:1002];
        if (!badgeLabelImageView) {
            badgeLabelImageView = [[UIImageView alloc] initWithImage:[UIImage imageNamed:@"payOptionLabelBackImage"]];
            badgeLabelImageView.tag = 1002;
            badgeLabelImageView.contentMode = UIViewContentModeScaleToFill;
            // 将背景图片插入到badgeLabel的下面
            [button insertSubview:badgeLabelImageView belowSubview:badgeLabel];
        }

        // 更新badgeLabel文本
        BOOL showBadge = [method[@"showBadge"] boolValue];
        if (showBadge) {
            NSString *badgeValue = method[@"badgeValue"];
            if (badgeValue && ![badgeValue isKindOfClass:[NSNull class]] && ![badgeValue isEqual:@""]) {
                badgeLabel.hidden = NO;
                badgeLabelImageView.hidden = NO;
                badgeLabel.text = badgeValue;
                [badgeLabel sizeToFit];

                CGFloat textWidth = CGRectGetWidth(badgeLabel.frame);
                CGFloat bgWidth = textWidth + ZOOM(12);
                CGFloat bgHeight = ZOOM(14);

                // 移除旧约束
                [badgeLabel mas_remakeConstraints:^(MASConstraintMaker *make) {
                    make.center.equalTo(badgeLabelImageView);
                }];

                [badgeLabelImageView mas_remakeConstraints:^(MASConstraintMaker *make) {
                    make.top.equalTo(button).offset(-ZOOM(7));
                    make.right.equalTo(button);
                    make.width.mas_equalTo(bgWidth);
                    make.height.mas_equalTo(bgHeight);
                }];
            } else {
                badgeLabel.hidden = YES;
                badgeLabelImageView.hidden = YES;
            }
        } else {
            badgeLabel.hidden = YES;
            badgeLabelImageView.hidden = YES;
        }
    }

    [self updateButtonsConstraints]; // 更新约束
}

- (void)updateButtonStyles {
    for (UIButton *button in self.paymentButtons) {
        if (button.hidden) continue;

        NSDictionary *methodData = [self methodDataForButton:button];
        if (!methodData) continue;

        BOOL isSelected = (button.tag == self.selectedPayMethod);
        NSString *iconName = methodData[@"icon"];
        NSString *title = methodData[@"title"];

        // 更新按钮样式
        UIView *containerView = button.subviews.firstObject;
        containerView.layer.borderColor = isSelected ? WBColorHex(0x333333).CGColor : WBColorHex(0x999999).CGColor;
        if (!self.isFromSinglePage) {
            containerView.backgroundColor = isSelected ? [UIColor whiteColor] : [UIColor clearColor];
            containerView.layer.borderWidth = isSelected ? ZOOM(1) : ZOOM(0.5);
        }
        UIImageView *imageView = containerView.subviews.firstObject;
        UILabel *label = containerView.subviews.lastObject;

        NSString *imageName = isSelected ? iconName : [iconName stringByAppendingString:@"-未选中"];
        imageView.image = [UIImage imageNamed:imageName];

        label.text = title;
        label.textColor = isSelected ? WBColorHex(0x333333) : WBColorHex(0x999999);
    }
    [[NSNotificationCenter defaultCenter] postNotificationName:WBSelectPayMethodNotification object:nil];
}


#pragma mark - lazy load

- (UIScrollView *)buttonsScrollView {
    if (!_buttonsScrollView) {
        _buttonsScrollView = [[UIScrollView alloc] init];
        _buttonsScrollView.showsHorizontalScrollIndicator = NO;
        _buttonsScrollView.showsVerticalScrollIndicator = NO;
        _buttonsScrollView.alwaysBounceHorizontal = YES;
        _buttonsScrollView.alwaysBounceVertical = NO;   // 禁止垂直方向回弹
    }
    return _buttonsScrollView;
}


@end

