- (void)setButtonSelected:(UIButton *)button {
    self.selectedButton = button;
    button.selected = YES;
}

- (void)setButtonDeselected:(UIButton *)button {
    button.selected = NO;
}

- (WBModule)getCurrentModule {
    WBModule currentModule;
    if (self.selectedButton == _vipButton) {
        currentModule = WBModuleVIP;
    } else if (self.selectedButton == _svipButton) {
        currentModule = WBModuleSVIP;
    } else {
        currentModule = WBModuleBenefit;
    }
    return currentModule;
}

+ (BOOL)checkIfCouldUsePromo:(WBProductModel *)productModel {
    BOOL isApplePay = productModel.selectedPaymethod & WBPaymentMethodApplePay;
    BOOL isAliPay = productModel.selectedPaymethod & WBPaymentMethodAliPay;
    BOOL isWechatPay = productModel.selectedPaymethod & WBPaymentMethodWechatPay;
    BOOL isSubscription = productModel.selectedPaymethod & WBPaymentMethodSubscription;
    if (isApplePay && !isAliPay && !isWechatPay && !isSubscription) {
        return FALSE;   // 当前选中的商品只携带苹果非连续订阅时，不允许使用优惠券
    }
    return TRUE;
}

+ (BOOL)isAppleSubscription:(WBProductModel *)productModel {
    BOOL isApplePay = productModel.selectedPaymethod & WBPaymentMethodApplePay;
    BOOL isSubscription = productModel.selectedPaymethod & WBPaymentMethodSubscription;
    if (isApplePay && isSubscription) {
        return TRUE;    // 苹果支付连续订阅
    }
    return FALSE;
}

+ (BOOL)isAppleNonSubscription:(WBProductModel *)productModel {
    BOOL isApplePay = productModel.selectedPaymethod & WBPaymentMethodApplePay;
    BOOL isSubscription = productModel.selectedPaymethod & WBPaymentMethodSubscription;
    if (isApplePay && !isSubscription) {
        return TRUE;    // 苹果支付非连续订阅
    }
    return FALSE;
}

// 判断是否是苹果连续订阅优惠券
+ (BOOL)isAppleSubscriptionPromo:(WBPromoModel *)promoModel {
    BOOL isApplePromo = promoModel.type & WBPromoTypeApplePay;
    BOOL isSubscriptionPromo = promoModel.type & WBPromoTypeSubscription;
    BOOL isAppleSubscriptionPromo = isApplePromo && isSubscriptionPromo;
    if (isAppleSubscriptionPromo) {
        return TRUE;
    }
    return FALSE;
}


#pragma mark - WBVipHeaderViewDelegate

- (void)headerViewDidClickLoginButton {
    if (kStringIsEmpty(WBSettingManager.sharedManager.Mobile)) {
        WBLoginViewController *loginVC = [[WBLoginViewController alloc] init];
        WBNavigationController *navVC = [[WBNavigationController alloc] initWithRootViewController:loginVC];
        navVC.modalPresentationStyle = UIModalPresentationFullScreen;
        [self presentViewController:navVC animated:YES completion:nil];
    }
}


#pragma mark - WBVipProductCollectionViewDelegate

- (void)didSelectProductModel:(WBProductModel *)productModel {
    self.selectedProductModel = productModel;
    [self updatePromoAndPurchaseView:productModel];
    [self updatePrivilegeViewForSelectedProduct:productModel];
    [self updateFloatingViewInnerLayout];
}

- (void)updatePrivilegeViewForSelectedProduct:(WBProductModel *)productModel {
    if (!productModel) return;
    if (self.selectedButton == self.benefitButton) return;

    NSString *vipClass = (productModel.typeFlags & WBProductTypeFlagVIPLevel) ? @"svip" : @"vip";
    [self.privilegeView updateUIWithVipClass:vipClass selectedProduct:productModel];
}

- (void)updatePromoAndPurchaseView:(WBProductModel *)selectedProduct {
    self.promoSectionView.productModel = selectedProduct;
    self.purchaseView.productModel = selectedProduct;
    [self.payOptionsView updateWithServerPayMethods:selectedProduct.serverPayMethods];
    [self updatePromoUserInfoLabel];
    [self updatePromoSectionHeight];
}


#pragma mark - WBPromoViewControllerDelegate

- (void)promoViewController:(WBPromoViewController *)promoVC didDismissWithPromoModels:(NSArray<WBPromoModel *> *)promoModels withSelectCount:(NSUInteger)selectCount andDiscountAmount:(CGFloat)discountAmount onProductId:(NSString *)productId {
    WBProductModel *product = [self getSelectedProductModel];
    NSParameterAssert([product.apple_product_id isEqualToString:productId]);
    if ([product.selectedPromoModels isEqual:promoModels]) return;  // double check
    product.selectedPromoModels = promoModels;
    self.promoSectionView.productModel = product;
    self.purchaseView.productModel = product;   // 更新商品模型（选择了优惠券之后，计算新的价格）
    [self updatePromoUserInfoLabel];
}

- (void)promoViewController:(WBPromoViewController *)promoVC didConformToConsumePromoModels:(NSArray<WBPromoModel *> *)promoModels withSelectCount:(NSUInteger)selectCount andDiscountAmount:(CGFloat)discountAmount onProductId:(NSString *)productId {
    [self.navigationController popViewControllerAnimated:true];
}


#pragma mark - WBPurchaseSectionViewDelegate

- (void)purchaseSectionViewPromoLimitTimeCountdownTimerEndCountDown:(WBPurchaseSectionView *)purchaseSectionView {
    [self updatePromoSectionHeight];
}


#pragma mark - WBPaymentProcessObserver

- (void)onOrderCreating {
    if (self.inFront) {
        [SVProgressHUD setDefaultMaskType:SVProgressHUDMaskTypeGradient];
        [SVProgressHUD showWithStatus:@"正在创建订单"];
    }
}

- (void)onOrderCreateFailed:(NSString *)error {
    if (self.inFront) {
        [SVProgressHUD dismiss];
        [WBVipViewController showErrorWithTitle:@"订单创建失败" message:error ?: @"请检查网络后重试" rightTitle:@"重试" confirmAction:^(UIAlertAction * _Nonnull action) {
            [self purchaseSelectedProduct];
        } cancelAction:^(UIAlertAction * _Nonnull action) {
        } currentViewController:self];
    }
}

- (void)onOrderRefreshing {
    if (self.inFront) {
        [SVProgressHUD setDefaultMaskType:SVProgressHUDMaskTypeGradient];
        [SVProgressHUD showWithStatus:@"正在充值会员"];
    }
}

