#pragma mark - Promo

- (void)loadPromos {
    [[WBNetworkManager defaultManager] requestAllHavePromoCodeWithCallback:^(NSArray<WBPromoModel *> * _Nullable promoModels, NSError * _Nullable error) {
        if (error) return;
        self.promos = promoModels ?: @[];
        [self parseAvailableAndUnavailablePromos];
        [self updatePromoInfoAndPurchaseButtonLabel:self.selectedProduct];
    }];
}

// 区分可用/不可用优惠券
- (void)parseAvailableAndUnavailablePromos {
    if (![self.promos count]) return;
    NSMutableArray<WBPromoModel *> *availablePromos = [NSMutableArray arrayWithCapacity:[self.promos count]];
    NSMutableArray<WBPromoModel *> *unavailablePromos = [NSMutableArray arrayWithCapacity:[self.promos count]];
    for (WBPromoModel *promoModel in self.promos) {
        if (promoModel.expired || promoModel.useDate != nil) {
            [unavailablePromos addObject:promoModel];
        } else {
            [availablePromos addObject:promoModel];
        }
    }
    self.availablePromos = [availablePromos copy];
    self.unavailablePromos = [unavailablePromos copy];
}

- (void)afterSelectPayMethod {
    WBProductModel *selectedProduct = [self getSelectedProductModel];
    selectedProduct.selectedPaymethod = self.payOptionsView.selectedPayMethod;
    selectedProduct.selectedPayMethodId = self.payOptionsView.selectedPayMethodId;
    if (selectedProduct.selectedPaymethod == WBPaymentMethodTaoBaoPay) {
        self.purchaseButton.hidden = YES;
        self.jumpButton.hidden = NO;
        self.promoContainerView.hidden = YES;
    } else {
        self.purchaseButton.hidden = NO;
        self.jumpButton.hidden = YES;
        self.promoContainerView.hidden = NO;
        [self updatePromoInfoAndPurchaseButtonLabel:self.selectedProduct];
    }
}

- (WBProductModel *)getSelectedProductModel {
    WBProductModel *product = self.productView.currentSelectedProduct.productModel;
    return product;
}

