- (void)showBottomPopup:(NSDictionary *)bottomPopupInfo {
    NSString *title = bottomPopupInfo[@"title"];
    NSString *content = bottomPopupInfo[@"content"];
    NSArray<NSString *> *keyWords = bottomPopupInfo[@"keyWords"];
    NSString *confirmString = bottomPopupInfo[@"confirmString"];
    NSString *cancelString = bottomPopupInfo[@"cancelString"];

    NSURL *confirmUrl = [NSURL URLWithString:bottomPopupInfo[@"confirmRoute"]];
    NSURL *cancelUrl = [NSURL URLWithString:bottomPopupInfo[@"cancelRoute"]];

    [WBAlertPopViewController alertWithTitle:title content:content keyWords:keyWords confirmText:confirmString cancelText:cancelString confirmAction:^{
        if (confirmUrl && confirmUrl.scheme.length) {
            [WBRouteManager.sharedManager performRoute:confirmUrl sourceInterface:@"bottomPopup"];
        }
    } cancelAction:^{
        if (cancelUrl && cancelUrl.scheme.length) {
            [WBRouteManager.sharedManager performRoute:cancelUrl sourceInterface:@"bottomPopup"];
        }
    }];
}


