+ (NSString*)getNetworkErrorMsg:(NSError * _Nullable)error {
    if (error == nil) {
        return @"无错误";
    }
    if ([error.domain compare:WBNetworkRequestErrorDomain] != 0) {
        return @"未知错误";
    } else {
        NSString *errorDesc = [error.userInfo objectForKey:NSLocalizedDescriptionKey];
        if (errorDesc) {
