@implementation WBAppConfig

+ (instancetype)sharedInstance {
    static id instance = nil;
    static dispatch_once_t onceToken;
    dispatch_once(&onceToken, ^{
        NSString *docPath = [self getDocumentPath];
        NSFileManager *fileManager = [NSFileManager defaultManager];
        if ([fileManager fileExistsAtPath:docPath]) {
            NSData *data = [NSData dataWithContentsOfFile:docPath];
            NSError *err = nil;
            id json = [NSJSONSerialization JSONObjectWithData:data options:NSJSONReadingFragmentsAllowed error:&err];
//            NSParameterAssert(!err);
			instance  = [[self alloc] initWithDict:json];
        } else {
            [fileManager createFileAtPath:docPath contents:nil attributes:nil];
			instance = [[self alloc] init];
        }
    });
    return instance;
}

- (instancetype)initWithDict:(NSDictionary *)dict {
	if (self = [self init]) {
		self.tips = dict[NSStringFromSelector(@selector(tips))];
//		self.shortcuts = [WBRichMessageLinkModel modelsWithDicts:dict[NSStringFromSelector(@selector(shortcuts))]];
	}
	return self;
}

