	return @{
		NSStringFromSelector(@selector(tips)): self.tips,
//		NSStringFromSelector(@selector(shortcuts)): [WBRichMessageLinkModel modelsToDicts:self.shortcuts]
	};
}

+ (NSString *)getCacheFilePath {
    NSString *cacheDir = [[WBStorageManager sharedManager] cacheRoot];
    NSString *cacheFile = [cacheDir stringByAppendingPathComponent:[WBUtility getCodeNameSaltedSha1Hash:@"app_config.json"]];
    return cacheFile;
}

+ (NSString *)getDocumentPath {
    NSString *docDir = [[WBStorageManager sharedManager] docRoot];
    NSString *docFile = [docDir stringByAppendingPathComponent:[WBUtility getCodeNameSaltedSha1Hash:@"app_config.json"]];
    return docFile;
}

- (void)write2Cache {
    [[[self convertToDict] mj_JSONData] writeToFile:[WBAppConfig getCacheFilePath] atomically:true];
}

- (void)write2Document {
    [[[self convertToDict] mj_JSONData] writeToFile:[WBAppConfig getDocumentPath] atomically:true];
}

- (void)dealloc {
    [[NSNotificationCenter defaultCenter] removeObserver:self];
}

@end

