@implementation WBAppManager




#pragma mark singleton

+ (void)load {
    NSLog(@"load WBAppManager sharedManager");
    [WBAppManager sharedManager];
}

+ (instancetype)sharedManager {
    static WBAppManager *defaultManager = nil;
    static dispatch_once_t onceToken;
    dispatch_once(&onceToken,^{
        defaultManager = [[self alloc] init];
    });

    return defaultManager;
}

- (instancetype)init {
    self = [super init];
    if (self) {
        [NSNotificationCenter.defaultCenter addObserver:self selector:@selector(onAppFinishLaunching) name:UIApplicationDidFinishLaunchingNotification object:nil];
        [NSNotificationCenter.defaultCenter addObserver:self selector:@selector(onAppEnterBackground) name:UIApplicationDidEnterBackgroundNotification object:nil];
        [NSNotificationCenter.defaultCenter addObserver:self selector:@selector(onAppEnterForeground) name:UIApplicationWillEnterForegroundNotification object:nil];
        [NSNotificationCenter.defaultCenter addObserver:self selector:@selector(onAppBecomeActive) name:UIApplicationDidBecomeActiveNotification object:nil];
        [NSNotificationCenter.defaultCenter addObserver:self selector:@selector(onAppResignActive) name:UIApplicationWillResignActiveNotification object:nil];
        [NSNotificationCenter.defaultCenter addObserver:self selector:@selector(onAppWillTerminate) name:UIApplicationWillTerminateNotification object:nil];

        _queue = dispatch_queue_create("__amqueue", NULL);
        _tokenRefreshStatus = tokenAwaitRefresh;
        _lastRequestTime = 0;
        _requestInterval = 0.8;
        _rootvc = [WBLaunchViewController class];
        _appBundlePath = [NSBundle mainBundle].bundlePath;
        _convertToVappVC = FALSE;
        _isBRootViewController = TRUE;
    }
    return self;
}

- (void)dealloc {
    NSLog(@"dealloc WBAppManager");
    [[NSNotificationCenter defaultCenter] removeObserver:self];
    [[UIScreen mainScreen] removeObserver:self forKeyPath:@"captured"];
    if (self.observingClazz) {
        [self removeObserver:self forKeyPath:@"clazz"];
        self.observingClazz = NO;
    }
}

#pragma mark lifecycle observer

- (void)onAppFinishLaunching {
    // Guest App launching msg
    static dispatch_once_t onceToken;// 使用 static 的 dispatch_once_t 来保证代码块只执行一次，无论应用程序启动多少次。
    dispatch_once(&onceToken, ^{
        NSLog(@"launching");
        LogApplicationState;// 调用 LogApplicationState 宏，打印应用程序当前的状态信息。
        [WBEventManager onAppFinishLaunching];// 通知事件管理器应用程序已完成启动。
        [[WBStorageManager sharedManager] fileSystemVersionCheck];// 检查并应用文件系统的版本更新。



        // if engine resource hash is set, it indicates that the user has seen face B
        // in such cases, remove the force face A restrictions
        if (IsInReview() == 0 &&
            (WBSettingManager.sharedManager.EngresHash != nil ||
            SecondsElapsedSincePack() > ABBridge_GetForceATimeInSeconds())) {
            [self observeNetworkStatus];// 开始监听网络状态。
            [self observeScreenShotAndScreenRecordEvent];// 开始监听截屏和录屏事件。
        } else {
            // 如果用户尚未看到过界面 B，则延迟0.1秒后在主队列上设置应用程序的根视图控制器为界面 A。
            // SHOW FACE A
            dispatch_after(dispatch_time_delay(0.1), dispatch_get_main_queue(), ^{
                // 获取界面 A 的视图控制器类，成功获取后就将其设置为根视图控制器
                Class clazz = ABBridge_GetARootViewControllerClass();
                if (clazz) {
                    [self setRootViewController:clazz];
                    self.isBRootViewController = FALSE;
                }
            });
        }
    });
}




