- (void)observeValueForKeyPath:(NSString *)keyPath ofObject:(id)object change:(NSDictionary<NSKeyValueChangeKey,id> *)change context:(void *)context {
    if ([object isEqual:[UIScreen mainScreen]] && [keyPath isEqualToString:@"captured"]) {
        BOOL isBegin = [change[NSKeyValueChangeNewKey] boolValue];
        [WBEventManager logAppScreenRecordEvent:isBegin];
        return;
    }
    if (object == self && [keyPath isEqualToString:@"clazz"]) {
        Class newClazz = change[NSKeyValueChangeNewKey];
        if (newClazz) {
            if (self.observingClazz) {
                [self removeObserver:self forKeyPath:@"clazz"];
                self.observingClazz = NO;
            }
            if (WBSettingManager.sharedManager.IsPretending) {
                newClazz = [WBSubMainViewController class];
            }
            self.clazz = newClazz;
            [self setRootViewController:newClazz];
            self.isBRootViewController = TRUE;
        }
        return;
    }
}

